import{_ as o,o as t,c as d,ae as i}from"./chunks/framework.DTwQaIIa.js";const f=JSON.parse('{"title":"Commands and Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"en/modules/forge/commands.md","filePath":"en/modules/forge/commands.md"}'),a={name:"en/modules/forge/commands.md"};function r(n,e,c,s,l,m){return t(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="commands-and-permissions" tabindex="-1">Commands and Permissions <a class="header-anchor" href="#commands-and-permissions" aria-label="Permalink to &quot;Commands and Permissions&quot;">​</a></h1><p>All EmakiForge commands are accessed through the root command <code>/emakiforge</code> (aliases <code>/eforge</code>, <code>/ef</code>).</p><h2 id="command-list" tabindex="-1">Command List <a class="header-anchor" href="#command-list" aria-label="Permalink to &quot;Command List&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Arguments</th><th>Description</th><th>Permission</th></tr></thead><tbody><tr><td><code>/ef help</code></td><td>—</td><td>Display help information</td><td>None</td></tr><tr><td><code>/ef forge</code></td><td><code>&lt;recipeID&gt;</code></td><td>Open the forging interface for the specified recipe</td><td><code>emakiforge.use</code></td></tr><tr><td><code>/ef book</code></td><td>—</td><td>Open the recipe book interface</td><td><code>emakiforge.book</code></td></tr><tr><td><code>/ef reload</code></td><td>—</td><td>Reload all configuration and resource files</td><td><code>emakiforge.reload</code></td></tr><tr><td><code>/ef list recipe</code></td><td>—</td><td>List all loaded recipes</td><td><code>emakiforge.admin</code></td></tr></tbody></table><h3 id="command-details" tabindex="-1">Command Details <a class="header-anchor" href="#command-details" aria-label="Permalink to &quot;Command Details&quot;">​</a></h3><p><strong><code>/ef forge &lt;recipeID&gt;</code></strong></p><p>Opens the forging GUI for the specified recipe. Players need to place blueprints and materials into the corresponding slots, then click the confirm button to execute forging.</p><p><strong><code>/ef book</code></strong></p><p>Opens the recipe book interface, displaying all recipes the player has permission to view. Supports pagination browsing.</p><p><strong><code>/ef reload</code></strong></p><p>Reloads the following resources:</p><ul><li><code>config.yml</code> main configuration</li><li><code>lang/</code> language files</li><li><code>gui/</code> GUI configurations</li><li><code>recipes/</code> recipe files</li><li><code>blueprints/</code> blueprint files</li><li><code>materials/</code> material files</li></ul><h2 id="permission-nodes" tabindex="-1">Permission Nodes <a class="header-anchor" href="#permission-nodes" aria-label="Permalink to &quot;Permission Nodes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Permission Node</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>emakiforge.use</code></td><td>Allow using forging functionality</td><td><code>true</code></td></tr><tr><td><code>emakiforge.book</code></td><td>Allow opening the recipe book</td><td><code>true</code></td></tr><tr><td><code>emakiforge.reload</code></td><td>Allow reloading configuration</td><td><code>op</code></td></tr><tr><td><code>emakiforge.admin</code></td><td>Admin permission (includes list viewing, etc.)</td><td><code>op</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>Recipe-level permissions can be configured individually in recipe files via the <code>permission</code> field, or more granular control can be achieved using <code>type: permission</code> conditions in <code>conditions</code>.</p></div>',15)])])}const h=o(a,[["render",r]]);export{f as __pageData,h as default};
